// ============================================================
// FORMAT TELEGRAM MESSAGE — v0.1.0
// Style: Style A (compact) + Style C news segmentation
// IDN-StockNews Market Briefing Pipeline
// ============================================================
// Inputs from Score & Rank node:
//   item.json.title, .link, .pubDate, .source,
//   .tickers[], .matchedKeyword, .finalScore
//
// IDN sources  : kontan-market, bisnis-market, detik-finance
// Intl sources : reuters-indonesia, bloomberg
//
// Telegram limits:
//   - Max 4096 chars per message
//   - parse_mode: Markdown
//   - disable_web_page_preview: true
// ============================================================

const IDN_SOURCES = new Set([
  'kontan-market', 'bisnis-market', 'detik-finance'
]);

const SOURCE_LABEL = {
  'kontan-market':   'Kontan',
  'bisnis-market':   'Bisnis.com',
  'detik-finance':   'Detik Finance',
  'reuters-indonesia': 'Reuters',
  'bloomberg':       'Bloomberg',
};

// ── Helpers ──────────────────────────────────────────────

function wibTime(date) {
  const wib = new Date(date.getTime() + 7 * 3600000);
  const hh = String(wib.getUTCHours()).padStart(2, '0');
  const mm = String(wib.getUTCMinutes()).padStart(2, '0');
  return `${hh}:${mm} WIB`;
}

function wibDateStr(date) {
  const wib = new Date(date.getTime() + 7 * 3600000);
  const months = ['January','February','March','April','May','June',
                  'July','August','September','October','November','December'];
  return `${wib.getUTCDate()} ${months[wib.getUTCMonth()]} ${wib.getUTCFullYear()}`;
}

function edition(date) {
  const wib = new Date(date.getTime() + 7 * 3600000);
  return wib.getUTCHours() < 12 ? 'Morning Edition' : 'Afternoon Edition';
}

function escMd(str) {
  // Escape Telegram Markdown special chars outside of link syntax
  return (str || '').replace(/([_*`\[\]])/g, '\\$1');
}

function articleTime(pubDate) {
  if (!pubDate) return '';
  const d = new Date(pubDate);
  if (isNaN(d)) return '';
  return wibTime(d);
}

function sourceLabel(src) {
  return SOURCE_LABEL[src] || src || 'Unknown';
}

// ── Build sections ────────────────────────────────────────

const items = $input.all();
const now   = new Date();
const SEP   = '─────────────────────────';

// Partition articles: IDN vs International
const idnArticles  = items.filter(i => IDN_SOURCES.has(i.json.source));
const intlArticles = items.filter(i => !IDN_SOURCES.has(i.json.source));

// ── HEADER ──
let msg = `*IDN Market Briefing — ${edition(now)}*\n`;
msg += `${wibDateStr(now)} | ${wibTime(now)}\n`;
msg += `${SEP}\n`;

// ── COMMODITY STATS ──
// Values are placeholders — replace with live data node upstream
msg += `\n*COMMODITY STATS*\n`;
msg += `Palm Oil   : 4,820 MYR/t   +1.2%\n`;
msg += `Coal       :   138.5 USD/t  -0.4%\n`;
msg += `Nickel     : 16,340 USD/t  +0.8%\n`;
msg += `CPO Index  :  4,105         +0.6%\n`;

// ── TOP GAINERS ──
// Values are placeholders — replace with live data node upstream
msg += `\n${SEP}\n`;
msg += `*TOP GAINERS — IDN STOCK*\n`;
msg += `Ticker  Daily   Weekly  Monthly\n`;
msg += `BBCA   +3.41%  +5.20%  +12.4%\n`;
msg += `GOTO   +2.87%  +4.10%   +8.7%\n`;
msg += `BMRI   +2.10%  +3.80%   +9.2%\n`;
msg += `ADRO   +1.95%  +6.40%  +18.1%\n`;
msg += `MTEL   +1.80%  +2.90%   +7.6%\n`;

msg += `\n*TOP GAINERS — US STOCK*\n`;
msg += `Ticker  Daily   Weekly  Monthly\n`;
msg += `NVDA   +4.21%  +9.20%  +31.5%\n`;
msg += `TSLA   +3.18%  +6.80%  +22.4%\n`;
msg += `META   +2.90%  +8.75%  +19.8%\n`;
msg += `AMZN   +1.75%  +5.90%  +14.2%\n`;
msg += `GOOG   +1.40%  +4.10%  +11.3%\n`;

msg += `\n*TOP GAINERS — CRYPTO*\n`;
msg += `Ticker  Daily   Weekly  Monthly\n`;
msg += `BTC    +2.90%  +8.40%  +22.4%\n`;
msg += `SOL    +4.11% +12.30%  +31.2%\n`;
msg += `ETH    +1.80%  +7.80%  +18.9%\n`;
msg += `BNB    +2.10%  +5.50%  +14.5%\n`;
msg += `AVAX   +3.50% +10.20%  +28.3%\n`;

// ── CORPORATE ACTION ──
// Placeholder — replace with live corporate action node upstream
msg += `\n${SEP}\n`;
msg += `*CORPORATE ACTION — IDN*\n`;
msg += `BBRI  Dividend      Rp 200/share   Record 20 Mar\n`;
msg += `TLKM  Rights Issue  1:5            Exercise 25 Mar\n`;
msg += `GOTO  Stock Split   1:10           Effective 1 Apr\n`;

// ── IDN NEWS (Style C: source + time under each item) ──
msg += `\n${SEP}\n`;
msg += `*# IDN NEWS*\n`;
if (idnArticles.length === 0) {
  msg += `_Tidak ada berita IDN terbaru._\n`;
} else {
  idnArticles.forEach((item, i) => {
    const a = item.json;
    const t = articleTime(a.pubDate);
    const src = sourceLabel(a.source);
    const timeStr = t ? ` | ${t}` : '';
    msg += `${i + 1}. [${escMd(a.title)}](${a.link})\n`;
    msg += `   ${src}${timeStr}\n`;
  });
}

// ── INTERNATIONAL NEWS (Style C) ──
msg += `\n*# INTERNATIONAL NEWS*\n`;
if (intlArticles.length === 0) {
  msg += `_No international news available._\n`;
} else {
  intlArticles.forEach((item, i) => {
    const a = item.json;
    const t = articleTime(a.pubDate);
    const src = sourceLabel(a.source);
    const timeStr = t ? ` | ${t}` : '';
    msg += `${i + 1}. [${escMd(a.title)}](${a.link})\n`;
    msg += `   ${src}${timeStr}\n`;
  });
}

// ── FOOTER ──
msg += `\n${SEP}\n`;
msg += `_IDN-StockNews v0.1.0_`;

// ── Telegram 4096-char guard ──
// If msg exceeds limit, split at the news section boundary.
const MAX = 4096;
const results = [];

if (msg.length <= MAX) {
  results.push({
    json: {
      text: msg,
      parse_mode: 'Markdown',
      disable_web_page_preview: true,
      article_count: items.length,
      idn_count: idnArticles.length,
      intl_count: intlArticles.length,
      edition: edition(now),
      generated_at: now.toISOString(),
      split: false,
    }
  });
} else {
  // Split point: between corporate action and IDN news
  const splitMarker = `\n${SEP}\n*# IDN NEWS*`;
  const splitIdx = msg.indexOf(splitMarker);
  const part1 = splitIdx > -1
    ? msg.slice(0, splitIdx) + `\n${SEP}\n_IDN-StockNews v0.1.0_`
    : msg.slice(0, MAX);
  const part2 = splitIdx > -1
    ? msg.slice(splitIdx)
    : msg.slice(MAX);
  results.push(
    { json: { text: part1, parse_mode: 'Markdown', disable_web_page_preview: true, split: true, part: 1 } },
    { json: { text: part2, parse_mode: 'Markdown', disable_web_page_preview: true, split: true, part: 2 } }
  );
}

return results;
